export const createSalarySlip = async (req, res) => {
    try {
        const companyId = getCompanyId(req);
        const {
            employeeId, month, year, presentDays, totalDutyHours,
            totalOtHours, otRatePH, grossPay, otPay, netPay, dailyLogs
