            employee: employeeId,
            month,
            year,
            workingDays: 30,
            presentDays: presentDays || 0,
            totalDutyHours: totalDutyHours || 0,
            otRatePH: otRatePH || 0,
            salaryComponents: {
                basic: employee.salary?.basic || 0,
                hra: employee.salary?.hra || 0,
