    const challan = await JobWorkChallan.findOneAndUpdate(
      { _id: id, company: companyId },
      req.body,
      { new: true }
    );
    res.status(200).json({ message: "Job Work Challan updated successfully", challan });
  } catch (error) {
    res.status(500).json({ message: error.message });
  }
};

